class Solution:
    def solve(self, costs: list[int]) -> int:
        costs.sort(reverse=True)
        ans = 0
        for i in range(1, len(costs)):
            ans += costs[i]
        return ans + costs[0]

def main():
    n = int(input())
    costs = list(map(int, input().split()))
    sol = Solution()
    print(sol.solve(costs))

if __name__ == '__main__':
    main()

