class Solution {
public:
    int solve(vector<int>& costs) {
        sort(costs.rbegin(), costs.rend());
        int ans = 0;
        for (int i = 1; i < costs.size(); i++)
            ans += costs[i];
        return ans + costs[0];
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> costs(n);
    for (int i = 0; i < n; i++)
        cin >> costs[i];
    Solution sol;
    cout << sol.solve(costs) << endl;
    return 0;
}
